     * Finds the smallest number >= startNum that satisfies the condition.
     * @param {number} startNum The starting number.
     * @param {boolean} targetIsPrime True if the target must be prime, false otherwise.
     * @returns {number} The minimum number of increments needed.
     */
    const findMinIncrements = (startNum, targetIsPrime) => {
        let currentNum = startNum;
        let increments = 0;

        while (true) {
            const isCurrentPrime = isPrime(currentNum);

            if (targetIsPrime) {
                // Target must be prime
                if (isCurrentPrime) {
                    return increments;
                }
            } else {
                // Target must be non-prime
                if (!isCurrentPrime) {
                    return increments;
                }
            }

            // If the condition is not met, increment and count
            currentNum++;
            increments++;
        }
    };

    let totalOperations = 0;

    for (let i = 0; i < nums.length; i++) {
        const num = nums[i];
        const isEvenIndex = i % 2 === 0;

        if (isEvenIndex) {
            // Even index: must be prime
            const increments = findMinIncrements(num, true);
            totalOperations += increments;
        } else {
            // Odd index: must be non-prime
            const increments = findMinIncrements(num, false);
            totalOperations += increments;
        }
    }

    return totalOperations;
